// Only process 'opened' events
// GitHub payload arrives nested under .body in n8n webhook node
const payload = $input.first().json.body;
const action = payload.action;
if (action && action !== 'opened') {
  return [];
}

const issue = payload.issue || {};
const repo = payload.repository || {};

const title = (issue.title || '').trim();
const body = issue.body || '';
const labels = (issue.labels || []).map(l => l.name || l).filter(Boolean).join(', ');
const repoName = repo.name || '';
const issueUrl = issue.html_url || issue.url || '';
const issueNumber = issue.number || 0;

if (!title) {
  return [{
    json: {
      issue: { title: '', body: '', labels: '', repoName, issueUrl, issueNumber },
      prompt: null,
      gemini_body_str: null,
      invalid_input: true,
      meta: { examples_used: 0 }
    }
  }];
}

// ── Knowledge Base (inlined from solutions/solution-b/knowledge-base.json) ──
const KNOWLEDGE_BASE = [
  {
    issue: { title: 'Authentication service fails in production after deployment', body: 'After the v2.3.1 deployment, the authentication service started returning 401 errors for all users. Users cannot log in. The service was working fine before the deployment. Logs show NullPointerException in AuthService.java:142. Rollback attempted but did not resolve the issue.', labels: ['bug', 'critical', 'backend'] },
    classification: { type: 'bug', severity: 'critical', component: 'backend', summary: 'Auth service returning 401 for all users post-deployment', reasoning: 'Production-breaking auth failure affecting all users with no working workaround; NullPointerException in backend service after deployment.' }
  },
  {
    issue: { title: 'Add rate limiting to REST API endpoints', body: 'We need to add rate limiting to our REST API to prevent abuse. Endpoints should be limited to 100 requests per minute per API key. This is needed to protect the service from denial-of-service attacks and ensure fair usage among clients.', labels: ['feature', 'backend', 'security'] },
    classification: { type: 'feature', severity: 'medium', component: 'backend', summary: 'Implement API rate limiting at 100 req/min per API key', reasoning: 'New functionality request for security hardening; existing features are unaffected, so severity is medium rather than critical.' }
  },
  {
    issue: { title: 'How do I reset my password through the API?', body: 'I am trying to reset my password programmatically via the API but I cannot find any endpoint for this in the documentation. Is there a password reset endpoint? What parameters does it accept? I checked the docs but nothing covers this case.', labels: ['question', 'documentation'] },
    classification: { type: 'question', severity: 'low', component: 'unknown', summary: 'User asking how to reset password via the API', reasoning: 'Interrogative phrasing, seeking clarification on API usage; no defect reported, component cannot be determined from context.' }
  },
  {
    issue: { title: 'Dashboard charts not rendering on Safari browsers', body: 'The analytics dashboard charts fail to render on Safari 16 and above on macOS. Users on Chrome and Firefox see the charts correctly. The browser console shows a TypeError related to the chart library canvas API usage. Approximately 25% of our user base uses Safari, so this is impacting a significant portion of users.', labels: ['bug', 'frontend', 'browser-compatibility'] },
    classification: { type: 'bug', severity: 'medium', component: 'frontend', summary: 'Charts fail to render on Safari due to canvas API TypeError', reasoning: 'Significant functionality impaired for Safari users (~25%); workaround exists (use Chrome or Firefox), so severity is medium.' }
  },
  {
    issue: { title: 'Add dark mode support to the settings page', body: 'Users have been requesting dark mode for some time. The settings page should have a toggle to switch between light and dark themes. The theme preference should be persisted in localStorage so it survives page refreshes.', labels: ['feature', 'frontend', 'ux'] },
    classification: { type: 'feature', severity: 'low', component: 'frontend', summary: 'Add dark mode toggle with localStorage persistence to settings page', reasoning: 'Nice-to-have UI enhancement; no existing functionality broken, making it a low-severity feature request.' }
  },
  {
    issue: { title: 'Button tooltip shows incorrect text on hover', body: 'The Save button in the user profile form shows Delete as its tooltip text when hovering. This appears to be a copy-paste error in the HTML template. The button itself works correctly and saves data as expected, so only the tooltip label is wrong.', labels: ['bug', 'frontend'] },
    classification: { type: 'bug', severity: 'low', component: 'frontend', summary: 'Save button displays incorrect Delete tooltip text due to copy-paste error', reasoning: 'Cosmetic bug with no functional impact; button operates correctly, minor UI inconsistency.' }
  },
  {
    issue: { title: 'What format does the API return dates in?', body: 'I am building an integration with the API and noticed that some endpoints return dates as Unix timestamps while others return ISO 8601 strings. Is there a documented standard format across all endpoints? Should I expect this to be consistent, or do I need to handle both formats in my client?', labels: ['question', 'api'] },
    classification: { type: 'question', severity: 'low', component: 'backend', summary: 'User asking about date format inconsistency across API endpoints', reasoning: 'Question about API behavior; no defect reported, user is seeking clarification on integration specifics.' }
  }
];

// ── Example selection helpers ──
const STOP_WORDS = new Set([
  'the', 'is', 'a', 'an', 'on', 'in', 'to', 'of', 'and', 'or',
  'for', 'with', 'when', 'this', 'that', 'it', 'my', 'i', 'be',
  'but', 'not'
]);
const LABEL_WEIGHT = 3;
const TITLE_WEIGHT = 2;
const BODY_WEIGHT = 1;
const EXAMPLE_BODY_MAX_CHARS = 300;

function tokenizeText(text) {
  if (!text || typeof text !== 'string') return new Set();
  const tokens = text.toLowerCase().match(/[a-z0-9]+/g) || [];
  return new Set(tokens.filter(t => t.length >= 2 && !STOP_WORDS.has(t)));
}

function normLabels(labelsArr) {
  if (!Array.isArray(labelsArr)) return [];
  return labelsArr.map(l => {
    const raw = typeof l === 'string' ? l : (l && l.name) || '';
    return raw.toLowerCase();
  }).filter(Boolean);
}

function intersectSize(setA, setB) {
  let count = 0;
  for (const item of setA) { if (setB.has(item)) count++; }
  return count;
}

function selectExamples(issueObj, kb, k) {
  if (!Array.isArray(kb) || kb.length === 0 || k === 0) return [];
  const issueLabels = new Set(normLabels(issueObj.labels));
  const issueTitleTokens = tokenizeText(issueObj.title);
  const issueBodyTokens = tokenizeText(issueObj.body);
  const scored = kb.map((entry, idx) => {
    const exLabels = new Set(normLabels(entry.issue.labels));
    const exTitle = tokenizeText(entry.issue.title);
    const exBody = tokenizeText(entry.issue.body);
    const score = LABEL_WEIGHT * intersectSize(issueLabels, exLabels)
                + TITLE_WEIGHT * intersectSize(issueTitleTokens, exTitle)
                + BODY_WEIGHT  * intersectSize(issueBodyTokens, exBody);
    return { entry, idx, score };
  });
  scored.sort((a, b) => b.score - a.score || a.idx - b.idx);
  if (scored[0].score === 0) return kb.slice(0, k);
  return scored.slice(0, k).map(s => s.entry);
}

function truncateBody(text) {
  if (!text || text.length <= EXAMPLE_BODY_MAX_CHARS) return text || '';
  return text.slice(0, EXAMPLE_BODY_MAX_CHARS) + '\u2026';
}

// ── Select relevant examples and build prompt ──
const issueForScoring = {
  title: title,
  body: body,
  labels: issue.labels || []
};
const selected = selectExamples(issueForScoring, KNOWLEDGE_BASE, 3);

const examplesBlock = selected.length > 0
  ? '\n\nExamples of correctly classified issues:\n\n' +
    selected.map((ex, i) => {
      const exTitle = (ex.issue && ex.issue.title) || '(no title)';
      const exBody = truncateBody((ex.issue && ex.issue.body) || '');
      const exLabels = Array.isArray(ex.issue && ex.issue.labels)
        ? ex.issue.labels.map(l => (typeof l === 'string' ? l : l.name || '')).join(', ')
        : '';
      const cl = ex.classification;
      return `Example ${i + 1}:\nIssue Title: ${exTitle}\nIssue Body: ${exBody || '(no body provided)'}\nLabels: ${exLabels || '(none)'}\nClassification:\n${JSON.stringify({ type: cl.type, severity: cl.severity, component: cl.component, summary: cl.summary, reasoning: cl.reasoning }, null, 2)}`;
    }).join('\n\n')
  : '';

const prompt = `You are an issue classifier for a software project. Analyze the GitHub issue below and return a JSON classification.

Return ONLY a valid JSON object with this exact structure:
{
  "type": "bug | feature | question",
  "severity": "critical | medium | low",
  "component": "frontend | backend | infra | unknown",
  "confidence": <float between 0.0 and 1.0>,
  "low_confidence": <boolean, true if confidence < 0.7>,
  "summary": "<one-line summary of the issue>",
  "reasoning": "<brief explanation of the classification>"
}

Classification rules:
- type=bug: reports something broken or not working as expected
- type=feature: requests new functionality or enhancement
- type=question: asks how something works or seeks clarification
- severity=critical: production-breaking, data loss, security vulnerability, auth failure in production
- severity=medium: significant functionality impaired but a workaround exists
- severity=low: minor issue, cosmetic problem, or nice-to-have improvement
- component=frontend: UI, CSS, JavaScript, browser-side behavior
- component=backend: API, database, server-side logic, authentication
- component=infra: deployment, CI/CD, Docker, cloud services, networking
- component=unknown: cannot determine from available context${examplesBlock}

Now classify this issue:

Issue Title: ${title}
Issue Body: ${body || '(no body provided)'}
Labels: ${labels || '(none)'}
Repository: ${repoName || '(unknown)'}

Return ONLY the JSON object. No markdown code blocks, no prose outside the JSON.`;

const geminiBodyStr = JSON.stringify({
  contents: [{ parts: [{ text: prompt }] }],
  generationConfig: { temperature: 0.1, maxOutputTokens: 512 }
});

return [{
  json: {
    issue: { title, body, labels, repoName, issueUrl, issueNumber },
    prompt,
    gemini_body_str: geminiBodyStr,
    invalid_input: false,
    meta: { examples_used: selected.length }
  }
}];

const prevData = $input.first().json;
const issueData = $('Build Prompt').first().json;
const issue = issueData.issue;

// Extract text from Gemini response
const candidates = (prevData.candidates || []);
const responseText = candidates[0]?.content?.parts?.[0]?.text || '';

// Parse and validate JSON
const VALID_TYPES = ['bug', 'feature', 'question'];
const VALID_SEVERITIES = ['critical', 'medium', 'low'];
const VALID_COMPONENTS = ['frontend', 'backend', 'infra', 'unknown'];

let jsonText = responseText.trim();
const codeBlockMatch = jsonText.match(/```(?:json)?\s*([\s\S]*?)```/);
if (codeBlockMatch) jsonText = codeBlockMatch[1].trim();

let classification;
try {
  const parsed = JSON.parse(jsonText);
  const type = VALID_TYPES.includes(parsed.type) ? parsed.type : 'unknown';
  const severity = VALID_SEVERITIES.includes(parsed.severity) ? parsed.severity : 'unknown';
  const component = VALID_COMPONENTS.includes(parsed.component) ? parsed.component : 'unknown';
  const confidence = typeof parsed.confidence === 'number'
    ? Math.min(1.0, Math.max(0.0, parsed.confidence))
    : 0.0;
  classification = {
    type, severity, component, confidence,
    low_confidence: confidence < 0.7,
    summary: typeof parsed.summary === 'string' ? parsed.summary : '',
    reasoning: typeof parsed.reasoning === 'string' ? parsed.reasoning : ''
  };
} catch (err) {
  classification = {
    type: 'unknown', severity: 'unknown', component: 'unknown',
    confidence: 0.0, low_confidence: true,
    summary: 'Failed to parse AI response',
    reasoning: `JSON parse error: ${err.message}`,
    parse_error: true
  };
}

// Determine Slack channel (without # for Slack API)
let slackChannel;
if (classification.type === 'question') {
  slackChannel = 'questions';
} else if (classification.type === 'bug' && classification.severity === 'critical') {
  slackChannel = 'incidents';
} else {
  slackChannel = 'backlog';
}

// Format Slack blocks
const severityEmoji = { critical: '🔴', medium: '🟡', low: '🟢', unknown: '⚪' };
const typeLabel = { bug: 'Bug', feature: 'Feature Request', question: 'Question', unknown: 'Unknown' };
const emoji = severityEmoji[classification.severity] || '⚪';
const typeStr = typeLabel[classification.type] || classification.type;
const confidenceNote = classification.low_confidence
  ? '\n⚠️ _Low confidence — manual review recommended_' : '';

const slackBodyStr = JSON.stringify({
  channel: slackChannel,
  text: `${emoji} [${typeStr}] ${issue.title}`,
  blocks: [
    {
      type: 'section',
      text: { type: 'mrkdwn', text: `${emoji} *[${typeStr}]* <${issue.issueUrl}|${issue.title}>` }
    },
    {
      type: 'section',
      fields: [
        { type: 'mrkdwn', text: `*Type:* ${classification.type}` },
        { type: 'mrkdwn', text: `*Severity:* ${classification.severity}` },
        { type: 'mrkdwn', text: `*Component:* ${classification.component}` },
        { type: 'mrkdwn', text: `*Confidence:* ${(classification.confidence * 100).toFixed(0)}%` }
      ]
    },
    {
      type: 'section',
      text: { type: 'mrkdwn', text: `*Summary:* ${classification.summary}${confidenceNote}` }
    }
  ]
});

// Format Sheets row
const processedAt = new Date().toISOString();
const sheetsRow = {
  timestamp: processedAt,
  issue_number: issue.issueNumber,
  title: issue.title,
  url: issue.issueUrl,
  type: classification.type,
  severity: classification.severity,
  component: classification.component,
  confidence: `${(classification.confidence * 100).toFixed(0)}%`,
  low_confidence: classification.low_confidence,
  ai_flagged: false,
  summary: classification.summary,
  reasoning: classification.reasoning
};

return [{ json: { issue, classification, slack_channel: slackChannel, slack_body_str: slackBodyStr, sheets_row: sheetsRow } }];
